import React from 'react'
import { useUserAuth } from '../context/UserAuthContext'
import { Navigate } from 'react-router-dom';

function protectedRoute({ children }) {

    const  { user } = UseUserAuth();

    if (!user){
        return <Navigate to="/" />
    }
  return children;
}

export default protectedRoute
